const booking = $json.booking || $json.body || $json;
const leadName = booking.lead_name || booking.name || '';
const phone = booking.phone_e164 || booking.phone || '';
const email = booking.email || booking.lead_email || '';

if (!booking.session_id || !leadName || (!phone && !email)) {
  throw new Error('Missing booking fields: session_id, lead_name/name, and at least one contact field (phone_e164/phone or email)');
}

const requestedDateTime = booking.requested_datetime || null;
let bookingDate = booking.booking_date || null;
let bookingTime = booking.booking_time || null;

if (requestedDateTime) {
  const parsed = new Date(requestedDateTime);
  if (!Number.isNaN(parsed.getTime())) {
    bookingDate = bookingDate || parsed.toISOString().slice(0, 10);
    bookingTime = bookingTime || parsed.toISOString().slice(11, 16);
  }
}

return [{
  json: {
    ...booking,
    lead_name: leadName,
    name: leadName,
    phone_e164: phone,
    phone,
    email,
    lead_email: email,
    requested_datetime: requestedDateTime,
    booking_date: bookingDate,
    booking_time: bookingTime,
    approval_status: 'pending',
    lifecycle_stage: 'meeting_requested',
    created_at: new Date().toISOString()
  }
}];

