const payload = $json.body || $json;
const decision = String(payload.decision || '').toLowerCase();
if (!['yes', 'approved', 'no', 'rejected'].includes(decision)) {
  throw new Error('decision must be yes/approved/no/rejected');
}

return [{
  json: {
    ...payload,
    decision,
    approved: decision === 'yes' || decision === 'approved',
    updated_at: new Date().toISOString()
  }
}];

